        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var student = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
