using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var items = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(2, result.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var items = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SinglePage_HasNoNavigation()
        {
            var items = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
            Assert.Equal(1, result.TotalPages);
        }
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var dept1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            var dept2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 80000m,
                StartDate = new DateTime(2019, 6, 1)
            };

            context.Departments.AddRange(dept1, dept2);

            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2015, 3, 15),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Jones",
                FirstMidName = "Jane",
                HireDate = new DateTime(2018, 8, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1,
                Department = dept1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2,
                Department = dept2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2021, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2022, 1, 15),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Adams",
                FirstMidName = "Charlie",
                EnrollmentDate = new DateTime(2020, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);

            var enrollment1 = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1001,
                StudentID = 1,
                Grade = Grade.A,
                Course = course1,
                Student = student1
            };
            var enrollment2 = new Enrollment
            {
                EnrollmentID = 2,
                CourseID = 1002,
                StudentID = 2,
                Grade = Grade.B,
                Course = course2,
                Student = student2
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);
            student1.Enrollments.Add(enrollment1);
            student2.Enrollments.Add(enrollment2);
            course1.Enrollments.Add(enrollment1);
            course2.Enrollments.Add(enrollment2);

            var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 1001, Instructor = instructor1, Course = course1 };
            context.CourseAssignments.Add(ca1);
            instructor1.CourseAssignments.Add(ca1);
            course1.CourseAssignments.Add(ca1);

            context.SaveChanges();
        }
    }
}

