                CourseAssignments = new List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Prof");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

