using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(System.IO.Path.GetTempPath());
            _mockEnv.Setup(e => e.ContentRootPath).Returns(System.IO.Path.GetTempPath());
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var result = _controller.Details(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Intro to CS", course.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithDepartments()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(3, _context.Courses.Count());
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            _controller.ModelState.AddModelError("Title", "Required");

            var result = _controller.Create(course, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Create_POST_WithInvalidFileExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Create_POST_WithOversizedFile_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsCourse()
        {
            var result = _controller.Edit(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Intro to CS", course.Title);
        }

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_POST_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1001);
            course.Title = "Updated Course";
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1
            };
            _controller.ModelState.AddModelError("Title", "Required");

            var result = _controller.Edit(course, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Edit_POST_WithInvalidFileExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Intro to CS",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.txt");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(course, viewResult.Model);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsCourse()
        {
            var result = _controller.Delete(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Intro to CS", course.Title);
        }

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1001);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(_context.Courses);
        }
    }
}

