                Name = "IncDept",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 8001,
                Title = "Inc Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment { CourseID = course.CourseID, StudentID = student.ID, Grade = Grade.B });
            _context.SaveChanges();

            var retrieved = _context.Students
                .Include(s => s.Enrollments)
                .ThenInclude(e => e.Course)
                .First(s => s.ID == student.ID);

            Assert.Single(retrieved.Enrollments);
            Assert.Equal("Inc Course", retrieved.Enrollments.First().Course.Title);
        }

        [Fact]
