                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var department = new Department
            {
                Name = "AdminDept",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructor.ID
            };
            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments
                .Include(d => d.Administrator)
                .First(d => d.Name == "AdminDept");

            Assert.NotNull(retrieved.Administrator);
            Assert.Equal("Admin", retrieved.Administrator.LastName);
        }

        [Fact]
        public void CanDeleteStudent()
        {
            var student = new Student
            {
                LastName = "ToDelete",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Students.Remove(student);
            _context.SaveChanges();

            Assert.Null(_context.Students.Find(student.ID));
        }

        [Fact]
        public void CanUpdateStudent()
        {
            var student = new Student
            {
                LastName = "Original",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new List<Enrollment>()
            };
