using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "TestLast");
            Assert.Equal("TestFirst", retrieved.FirstMidName);
            Assert.Equal(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Prof");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.First(c => c.CourseID == 5001);
            Assert.Equal("Test Course", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 75000m,
                StartDate = new DateTime(2019, 8, 1)
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Science");
            Assert.Equal(75000m, retrieved.Budget);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            _context.Students.Add(student);

            var dept = new Department
            {
                Name = "EnrollDept",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 6001,
                Title = "Enroll Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                CourseID = course.CourseID,
                StudentID = student.ID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID);
            Assert.Equal(Grade.A, retrieved.Grade);
            Assert.Equal(course.CourseID, retrieved.CourseID);
        }

        [Fact]
        public void CanAddCourseAssignment()
        {
            var instructor = new Instructor
            {
                LastName = "AssignProf",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "AssignDept",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 7001,
                Title = "Assign Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.First(ca => ca.InstructorID == instructor.ID);
            Assert.Equal(course.CourseID, retrieved.CourseID);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            var instructor = new Instructor
            {
                LastName = "OfficeProf",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Building A Room 200"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.First(o => o.InstructorID == instructor.ID);
            Assert.Equal("Building A Room 200", retrieved.Location);
        }

        [Fact]
        public void Student_IncludeEnrollments_Works()
        {
            var student = new Student
            {
                LastName = "IncTest",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1),
                Enrollments = new List<Enrollment>()
            };
            _context.Students.Add(student);

            var dept = new Department
            {
                Name = "IncDept",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 8001,
                Title = "Inc Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment { CourseID = course.CourseID, StudentID = student.ID, Grade = Grade.B });
            _context.SaveChanges();

            var retrieved = _context.Students
                .Include(s => s.Enrollments)
                .ThenInclude(e => e.Course)
