using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsCorrectFormat()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Student_HasEnrollments_Collection()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            };

            student.Enrollments.Add(new Enrollment { EnrollmentID = 1 });
            Assert.Single(student.Enrollments);
        }

        [Fact]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "Jane",
                HireDate = DateTime.Today
            };

            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 100,
                Title = "Test Course",
                Credits = 4,
                DepartmentID = 1
            };

            Assert.Equal(100, course.CourseID);
