        Name = "Mathematics",
        Budget = 80000m,
        StartDate = new DateTime(2019, 6, 1)
    };

    context.Departments.AddRange(dept1, dept2);
    context.SaveChanges();

    var instructor1 = new Instructor
    {
        LastName = "Smith",
        FirstMidName = "John",
        HireDate = new DateTime(2015, 3, 15),
        CourseAssignments = new List<CourseAssignment>(),
        OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
    };
    var instructor2 = new Instructor
    {
        LastName = "Jones",
        FirstMidName = "Jane",
        HireDate = new DateTime(2018, 8, 1),
        CourseAssignments = new List<CourseAssignment>()
    };

    context.Instructors.AddRange(instructor1, instructor2);
    context.SaveChanges();

    var course1 = new Course
    {
        CourseID = 1001,
        Title = "Intro to CS",
        Credits = 3,
        DepartmentID = 1,
        Enrollments = new List<Enrollment>(),
        CourseAssignments = new List<CourseAssignment>()
    };
    var course2 = new Course
    {
        CourseID = 1002,
        Title = "Calculus",
        Credits = 4,
        DepartmentID = 2,
        Enrollments = new List<Enrollment>(),
        CourseAssignments = new List<CourseAssignment>()
    };

    context.Courses.AddRange(course1, course2);
    context.SaveChanges();

    var student1 = new Student
    {
        LastName = "Doe",
        FirstMidName = "Alice",
        EnrollmentDate = new DateTime(2021, 9, 1),
        Enrollments = new List<Enrollment>()
    };
    var student2 = new Student
    {
        LastName = "Brown",
        FirstMidName = "Bob",
        EnrollmentDate = new DateTime(2022, 1, 15),
        Enrollments = new List<Enrollment>()
    };
    var student3 = new Student
    {
        LastName = "Adams",
        FirstMidName = "Charlie",
        EnrollmentDate = new DateTime(2020, 9, 1),
        Enrollments = new List<Enrollment>()
    };

    context.Students.AddRange(student1, student2, student3);
    context.SaveChanges();

    var enrollment1 = new Enrollment
    {
        CourseID = 1001,
        StudentID = student1.ID,
        Grade = Grade.A
    };
    var enrollment2 = new Enrollment
    {
        CourseID = 1002,
        StudentID = student2.ID,
        Grade = Grade.B
    };

    context.Enrollments.AddRange(enrollment1, enrollment2);
    context.SaveChanges();

    var ca1 = new CourseAssignment { InstructorID = instructor1.ID, CourseID = 1001 };
    context.CourseAssignments.Add(ca1);
    context.SaveChanges();
}

